class Hotkeys {
constructor(store, log) { this.store = store; this.log = log; this.bindings = store.get('hotkeys', DEFAULTS.hotkeys); this.handlers = {}; }
wire(handlers) {
this.handlers = handlers;
this._onKey = (e) => this._onKeyDown(e);
window.addEventListener('keydown', this._onKey, true);
}
unwire() { window.removeEventListener('keydown', this._onKey, true); }
_matches(e, combo) {
if (!combo) return false;
const parts = combo.split('+');
const code = parts[parts.length - 1];
const needShift = parts.includes('Shift'), needAlt = parts.includes('Alt'), needCtrl = parts.includes('Ctrl');
return e.code === code && e.shiftKey === needShift && e.altKey === needAlt && e.ctrlKey === needCtrl;
}
_onKeyDown(e) {
const t = e.target;
if (t && (/input|textarea|select/i.test(t.tagName) || t.isContentEditable)) return;
if (e.repeat) return;
for (const action in this.bindings) {
if (this._matches(e, this.bindings[action])) {
e.preventDefault();
try { this.handlers[action] && this.handlers[action](); } catch (err) { this.log.error('hotkey ' + action, String(err)); }
}
}
}
}
